class HomeActivity : ComponentActivity() {
  override fun onCreate(savedInstanceState: Bundle?) {
    super.onCreate(savedInstanceState)
    setContentView(R.layout.activity_home)
    if (savedInstanceState == null) {
      // first launch only
      Analytics.track("home_open")
    } else {
      restoreFromBundle(savedInstanceState)
    }
  }

  override fun onResume() {
    super.onResume()
    locationClient.start()
  }

  override fun onPause() {
    super.onPause()
    locationClient.stop()      // pause work that doesn't need to run when not in front
  }

  override fun onSaveInstanceState(out: Bundle) {
    out.putString("draft", draft)
    super.onSaveInstanceState(out)
  }

  override fun onDestroy() {
    super.onDestroy()
    if (isFinishing) cleanupLocalState()
    // configuration changes also call onDestroy — don't tear down view-model state here
  }
}

// Modern Android: use lifecycleScope + repeatOnLifecycle for flow collection
// lifecycleScope.launch { repeatOnLifecycle(Lifecycle.State.STARTED) { vm.state.collect { ... } } }

class ProfileFragment : Fragment(R.layout.fragment_profile) {
  private val vm: ProfileViewModel by viewModels()

  override fun onViewCreated(view: View, savedInstanceState: Bundle?) {
    super.onViewCreated(view, savedInstanceState)
    val nameView = view.findViewById<TextView>(R.id.name)

    // Use viewLifecycleOwner for view-bound flow collection — avoid leaks
    viewLifecycleOwner.lifecycleScope.launch {
      viewLifecycleOwner.repeatOnLifecycle(Lifecycle.State.STARTED) {
        vm.profile.collect { p -> nameView.text = p.name }
      }
    }
  }

  override fun onDestroyView() {
    // viewLifecycleOwner is destroyed; bound coroutines auto-cancel
    super.onDestroyView()
  }
}

