// Activity Result API — modern way to receive a result back
class HomeActivity : ComponentActivity() {
  private val pickContact = registerForActivityResult(
    ActivityResultContracts.PickContact()
  ) { uri: Uri? ->
    if (uri != null) handleContact(uri)
  }

  fun pick() = pickContact.launch(null)
  fun handleContact(uri: Uri) {}
}

// Open a specific image picker (modern photo picker)
val pickImage = registerForActivityResult(
  ActivityResultContracts.PickVisualMedia()
) { uri ->
  if (uri != null) showImage(uri)
}
pickImage.launch(PickVisualMediaRequest(ActivityResultContracts.PickVisualMedia.ImageOnly))

// Verify implicit intents resolve before launching (avoid ActivityNotFoundException)
if (intent.resolveActivity(packageManager) != null) startActivity(intent)

// ViewModel — most state goes here
class HomeViewModel(private val state: SavedStateHandle) : ViewModel() {
  private val _query = state.getStateFlow("query", "")
  val query: StateFlow<String> = _query

  fun update(q: String) { state["query"] = q }
}

// Bundle in Activity / Fragment for non-VM state
class HomeActivity : ComponentActivity() {
  private var draft: String = ""
  override fun onCreate(savedInstanceState: Bundle?) {
    super.onCreate(savedInstanceState)
    draft = savedInstanceState?.getString("draft") ?: ""
  }
  override fun onSaveInstanceState(out: Bundle) {
    out.putString("draft", draft)
    super.onSaveInstanceState(out)
  }
}

// Compose — rememberSaveable equivalent
@Composable
fun Form() {
  var draft by rememberSaveable { mutableStateOf("") }
  TextField(value = draft, onValueChange = { draft = it })
}

